-- ============================================================
-- 4. 验证插入的数据
-- ============================================================

-- 总商机数
SELECT COUNT(*) AS total_business FROM crm_business WHERE deleted = 0 AND creator = '1';

-- 按状态统计
SELECT
  CASE end_status
    WHEN NULL THEN '进行中'
    WHEN 1 THEN '已赢单'
    WHEN 2 THEN '已输单'
  END AS status_name,
  COUNT(*) AS cnt,
  SUM(total_price) AS total_amount
FROM crm_business
WHERE deleted = 0 AND creator = '1'
GROUP BY end_status
ORDER BY status_name;

-- 按阶段统计
SELECT s.percent AS stage_percent, COUNT(*) AS cnt, SUM(b.total_price) AS total_amount
FROM crm_business b
JOIN crm_business_status s ON b.status_id = s.id
WHERE b.deleted = 0 AND b.creator = '1'
GROUP BY s.id, s.percent
ORDER BY s.percent;

-- 预测金额计算验证（手动计算）
-- 进行中商机加权预测金额 = SUM(total_price * percent / 100)
SELECT
  SUM(CASE WHEN b.end_status IS NULL THEN b.total_price * s.percent / 100 ELSE 0 END) AS forecast_in_progress,
  SUM(CASE WHEN b.end_status = 1 THEN b.total_price ELSE 0 END) AS won_amount,
  SUM(CASE WHEN b.end_status IS NULL THEN b.total_price ELSE 0 END) AS in_progress_amount,
  SUM(CASE WHEN b.end_status = 2 THEN b.total_price ELSE 0 END) AS lost_amount
FROM crm_business b
JOIN crm_business_status s ON b.status_id = s.id
WHERE b.deleted = 0 AND b.creator = '1';

-- 商机产品行数
SELECT COUNT(*) AS product_line_count FROM crm_business_product WHERE deleted = 0;

SET FOREIGN_KEY_CHECKS = 1;

-- ============================================================
-- 执行完毕。预期结果：
--   - 总商机数: 40
--   - 进行中: 20 条，覆盖 5 个阶段
--   - 已赢单: 12 条（其中 4 条为去年同期成交）
--   - 已输单: 8 条
--   - 商机产品行: 12 条
